type CreateTaskInput = { description: string };

export const createTask: CreateTask<CreateTaskInput, Task> = async (
  { description },
  context
) => {
  // Find the max position to assign next available position
  const lastTask = await context.entities.Task.findFirst({
    orderBy: { position: "desc" },
  });
  const nextPosition = lastTask ? lastTask.position + 1 : 1;

  return context.entities.Task.create({
    data: {
      description,
      position: nextPosition,
    },
  });
};

type MoveTaskUpInput = { taskId: number };

