import { getTasks, createTask, moveTaskUp } from "wasp/client/operations";
import { type Task } from "wasp/entities";

export function MainPage() {
  const [description, setDescription] = useState("");
  const { data: tasks, isLoading, error } = useQuery(getTasks);

  const moveTaskUpOptimistic = useAction(moveTaskUp, {
    optimisticUpdates: [
      {
        getQuerySpecifier: () => [getTasks],
        updateQuery: ({ taskId }, oldData) => {
          if (!oldData) return oldData;

          const tasks = oldData as Task[];
          const taskIndex = tasks.findIndex((t) => t.id === taskId);

          if (taskIndex <= 0) return tasks;

          const updatedTasks = [...tasks];
          const taskToMove = updatedTasks[taskIndex];
          const taskAbove = updatedTasks[taskIndex - 1];

          // Swap positions in local cache
          updatedTasks[taskIndex - 1] = {
            ...taskToMove,
            position: taskAbove.position,
          };
          updatedTasks[taskIndex] = {
            ...taskAbove,
            position: taskToMove.position,
          };

          return updatedTasks;
        },
      },
    ],
  });

  async function handleCreateTask(e: React.FormEvent) {
    e.preventDefault();
    if (!description.trim()) return;
    await createTask({ description });
    setDescription("");
  }

  async function handleMoveUp(taskId: number) {
    await moveTaskUpOptimistic({ taskId });
  }

  if (isLoading) return <div style={styles.container}>Loading tasks...</div>;
  if (error)
    return (
      <div style={styles.container}>Error loading tasks: {error.message}</div>
    );

  return (
    <div style={styles.container}>
      <h1 style={styles.heading}>Task Reorder (Optimistic Updates)</h1>

      <form onSubmit={handleCreateTask} style={style

